+// Zerobuf tag constants (must match zerobuf.zig Tag enum)
+export const ZB_TAG_NULL = 0;
+export const ZB_TAG_BOOL = 1;
+export const ZB_TAG_I32 = 2;
+export const ZB_TAG_F64 = 3;
+export const ZB_TAG_STRING = 4;
